func TestCompactDiffFormatter_Format_NoChanges(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{},
		},
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	if result != "No changes planned\n" {
		t.Errorf("Expected 'No changes planned\\n', got %q", result)
	}
}

func TestCompactDiffFormatter_Format_NilPlan(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	result := formatter.Format(nil, &schemarepo.Schemas{})

	if result != "" {
		t.Errorf("Expected empty string for nil plan, got %q", result)
	}
}

func TestCompactDiffFormatter_Format_NilChanges(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	plan := &plans.Plan{
		Changes: nil,
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	if result != "" {
		t.Errorf("Expected empty string for nil changes, got %q", result)
	}
}

func TestCompactDiffFormatter_Format_CreateResource(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a simple test resource change
	addr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: "aws_instance",
				Name: "example",
			},
			Key: nil,
		},
	}

	change := &plans.ResourceInstanceChangeSrc{
		Addr:       addr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{change},
		},
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	// Check that the output contains the expected elements
	if result == "" {
		t.Error("Expected non-empty output")
	}
	if !contains(result, "Create:") {
		t.Errorf("Expected 'Create:' in output, got:\n%s", result)
	}
	if !contains(result, "aws_instance.example") {
		t.Errorf("Expected 'aws_instance.example' in output, got:\n%s", result)
	}
	if !contains(result, "Summary:") {
		t.Errorf("Expected 'Summary:' in output, got:\n%s", result)
	}
}

func TestCompactDiffFormatter_Format_MultipleActions(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create resources with different actions
	createAddr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: "aws_instance",
				Name: "create_me",
			},
			Key: nil,
		},
	}

	updateAddr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: "aws_instance",
				Name: "update_me",
			},
			Key: nil,
		},
	}

	deleteAddr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: "aws_instance",
				Name: "delete_me",
			},
			Key: nil,
		},
	}

	createChange := &plans.ResourceInstanceChangeSrc{
		Addr:       createAddr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	}

	updateChange := &plans.ResourceInstanceChangeSrc{
		Addr:       updateAddr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Update,
		},
	}

	deleteChange := &plans.ResourceInstanceChangeSrc{
		Addr:       deleteAddr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Delete,
		},
	}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				createChange,
				updateChange,
				deleteChange,
			},
		},
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	// Check that all actions are present
	if !contains(result, "Create:") {
		t.Errorf("Expected 'Create:' in output")
	}
	if !contains(result, "Update:") {
		t.Errorf("Expected 'Update:' in output")
	}
	if !contains(result, "Delete:") {
		t.Errorf("Expected 'Delete:' in output")
	}

	// Check that all resources are present
	if !contains(result, "aws_instance.create_me") {
		t.Errorf("Expected 'aws_instance.create_me' in output")
	}
	if !contains(result, "aws_instance.update_me") {
		t.Errorf("Expected 'aws_instance.update_me' in output")
	}
	if !contains(result, "aws_instance.delete_me") {
		t.Errorf("Expected 'aws_instance.delete_me' in output")
	}

	// Check summary shows 3 changes
	if !contains(result, "Summary: 3 resource(s)") {
		t.Errorf("Expected 'Summary: 3 resource(s)' in output, got:\n%s", result)
	}
}

