func TestCompactDiffFormatter_Format_SkipsDeposedKeys(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a change with a deposed key
	addr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: "aws_instance",
				Name: "deposed",
			},
			Key: nil,
		},
	}

	// Use a non-NotDeposed key
	deposedKey := states.DeposedKey("some_key")

	deposedChange := &plans.ResourceInstanceChangeSrc{
		Addr:       addr,
		DeposedKey: deposedKey,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Delete,
		},
	}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{deposedChange},
		},
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	// Should show "No changes planned" since deposed is skipped
	if result != "No changes planned\n" {
		t.Errorf("Expected 'No changes planned\\n', got:\n%s", result)
	}
}

func TestCompactDiffFormatter_Format_DataSource(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a data source read
	addr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.DataResourceMode,
				Type: "aws_ami",
				Name: "example",
			},
			Key: nil,
		},
	}

	change := &plans.ResourceInstanceChangeSrc{
		Addr:       addr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Read,
		},
	}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{change},
		},
	}

