			},
			Key: nil,
		},
	}

	deleteAddr := addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: "aws_instance",
				Name: "delete_me",
			},
			Key: nil,
		},
	}

	createChange := &plans.ResourceInstanceChangeSrc{
		Addr:       createAddr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	}

	updateChange := &plans.ResourceInstanceChangeSrc{
		Addr:       updateAddr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Update,
		},
	}

	deleteChange := &plans.ResourceInstanceChangeSrc{
		Addr:       deleteAddr,
		DeposedKey: states.NotDeposed,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Delete,
		},
	}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				createChange,
				updateChange,
				deleteChange,
			},
		},
	}

	result := formatter.Format(plan, &schemarepo.Schemas{})

	// Check that all actions are present
	if !contains(result, "Create:") {
		t.Errorf("Expected 'Create:' in output")
	}
	if !contains(result, "Update:") {
		t.Errorf("Expected 'Update:' in output")
	}
	if !contains(result, "Delete:") {
		t.Errorf("Expected 'Delete:' in output")
	}

	// Check that all resources are present
	if !contains(result, "aws_instance.create_me") {
		t.Errorf("Expected 'aws_instance.create_me' in output")
	}
	if !contains(result, "aws_instance.update_me") {
		t.Errorf("Expected 'aws_instance.update_me' in output")
	}
	if !contains(result, "aws_instance.delete_me") {
		t.Errorf("Expected 'aws_instance.delete_me' in output")
	}

	// Check summary shows 3 changes
