	// Use a non-NotDeposed key
	deposedKey := states.DeposedKey("some_key")

	deposedChange := &plans.ResourceInstanceChangeSrc{
		Addr:       addr,
		DeposedKey: deposedKey,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Delete,
		},
